+    pub diag_pivot_thresh: f64,
+}
+
+impl Default for LuOptions {
+    fn default() -> Self {
+        Self {
+            mode: RuntimeMode::Strict,
+            ordering: PermutationOrdering::Colamd,
+            diag_pivot_thresh: 1.0,
+        }
+    }
+}
